using namespace adsk::core;
using namespace adsk::fusion;

Ptr ui;

extern "C" XI_EXPORT bool run(const char* context)
{
    Ptr app = Application::get();
    if (!app)
        return false;

    ui = app->userInterface();
    if (!ui)
        return false;


    // Get active design
    Ptr product = app->activeProduct();
    if (!product)
        return false;

    Ptr design = product;
    if (!design)
        return false;

    // Get root component in this design
    Ptr rootComp = design->rootComponent();
    if (!rootComp)
        return false;

    // Get the first sub component
    Ptr occs = rootComp->occurrences();
    if (!occs)
        return false;

    Ptr firstOcc = occs->item(0);
    if (!firstOcc)
        return false;

    Ptr subComp1 = firstOcc->component();
    if (!subComp1)
        return false;

    // Get the second sub component
    Ptr secondOcc = occs->item(1);
    if (!secondOcc)
        return false;

    Ptr subComp2 = secondOcc->component();
    if (!subComp2)
        return false;

    // Get the first body in sub component 1
    Ptr bodiesInSubComp1 = subComp1->bRepBodies();
    if (!bodiesInSubComp1)
        return false;

    Ptr bodyInSubComp1 = bodiesInSubComp1->item(0);
    if (!bodyInSubComp1)
        return false;

    // Cut/paste body from sub component 1 to sub component 2
    Ptr featuresInSubComp2 = subComp2->features();
    if (!featuresInSubComp2)
        return false;

    Ptr cutPasteBodiesInSubComp2 = featuresInSubComp2->cutPasteBodies();
    if (!cutPasteBodiesInSubComp2)
        return false;

    Ptr cutPasteBody = cutPasteBodiesInSubComp2->add(bodyInSubComp1);
    if (!cutPasteBody)
        return false;

    // Cut/paste bodies from sub component to root component
    Ptr bodyCollection = ObjectCollection::create();
    if (!bodyCollection)
        return false;

    Ptr bodiesInSubComp2 = subComp2->bRepBodies();
    if (!bodiesInSubComp2)
        return false;

    for (size_t i = 0; i count(); ++i)
        bodyCollection->add(bodiesInSubComp2->item(i));

    Ptr featuresInRoot = rootComp->features();
    if (!featuresInRoot)
        return false;

    Ptr cutPasteBodiesInRoot = featuresInRoot->cutPasteBodies();
    if (!cutPasteBodiesInRoot)
        return false;

    cutPasteBody = cutPasteBodiesInRoot->add(bodyCollection);
    if (!cutPasteBody)
        return false;

    // Dump the information of Cut Paste Body in root component
    for (size_t i = 0; i count(); ++i)
    {
        cutPasteBody = cutPasteBodiesInRoot->item(i);
        if (!cutPasteBody)
            return false;

        std::string cutPasteBodyInfo = "CutPasteBody: name - " + cutPasteBody->name();
         ui->messageBox(cutPasteBodyInfo);
    }


    return true;
}
